        os.write(fd, str(os.getpid()).encode())
        os.close(fd)
        return True
    except FileExistsError:
        # Stale lock: if owner process is dead, reclaim it
        try:
            owner_pid = int(LOCK_FILE.read_text().strip())
            os.kill(owner_pid, 0)  # raises if process doesn't exist
